        public static void GetUsageItem(this ServerSockets.Packet msg, out ItemUsuageID action, out uint id, out ulong dwParam, out uint timestamp, out uint dwParam2, out uint dwParam3, out uint dwparam4, out ulong Money, out uint dwparam5, out List<uint> args, out MsgItemProto Proto)
        {
            var Info = new MsgItemProto();
            Info = msg.ProtoBufferDeserialize(Info);
            action = (ItemUsuageID)Info.action;
            id = (uint)Info.id;
            dwParam = Info.dwParam;
            timestamp = (uint)Info.timestamp;
            dwParam2 = (uint)Info.dwParam2;
            dwParam3 = (uint)Info.dwParam3;
            dwparam4 = (uint)Info.dwparam4;
            dwparam5 = (uint)Info.RelicAttributes;
            Money = Info.MoneyWareHouse;
            args = Info.args;
            Proto = Info;
        }
        public unsafe static ServerSockets.Packet ItemUsageCreate(this ServerSockets.Packet msg, ItemUsuageID action, uint id, ulong dwParam1, uint timestamp, uint dwParam2, uint dwParam3, uint dwparam4, ulong Money, List<uint> args = null)
        {
            msg.InitWriter();
            var Info = new MsgItemProto()
            {
                action = (ulong)action,
                id = id,
                dwParam = dwParam1,
                timestamp = (timestamp != 0) ? timestamp : (uint)DateTime.Now.Value(),
                dwParam2 = dwParam2,
                dwParam3 = dwParam3,
                dwparam4 = dwparam4,
                MoneyWareHouse = Money,

            };
            if (args != null)
            {
                Info.args = args;
            }
            msg.ProtoBufferSerialize(Info);
            msg.Finalize(GamePackets.MsgItem);
            return msg;
        }
        public unsafe static ServerSockets.Packet ItemUsageCreate(this ServerSockets.Packet msg, ItemUsuageID action, uint id, ulong dwParam1, uint timestamp, uint dwParam2, uint dwParam3, uint dwparam4, List<uint> args = null, uint dwparam5 = 0)
        {
            msg.InitWriter();
            var Info = new MsgItemProto()
            {
                action = (ulong)action,
                id = id,
                dwParam = dwParam1,
                timestamp = (timestamp != 0) ? timestamp : (uint)DateTime.Now.Value(),
                dwParam2 = dwParam2,
                dwParam3 = dwParam3,
                dwparam4 = dwparam4,
                RelicAttributes = dwparam5,
            };
            if (args != null)
            {
                Info.args = args;
            }
            msg.ProtoBufferSerialize(Info);
            msg.Finalize(GamePackets.MsgItem);
            return msg;
        }
        public unsafe static ServerSockets.Packet ItemUsageCreate(this ServerSockets.Packet msg, MsgItemProto obj)
        {
            msg.InitWriter();
            msg.ProtoBufferSerialize(obj);
            msg.Finalize(GamePackets.MsgItem);
            return msg;
        }

