                            if (!client.Player.TREPIN2 && client.Player.CheckPin() && item.AnimaItemID > 0 || !client.Player.TREPIN2 && client.Player.CheckPin() && item.ITEM_ID >= 4200001 && item.ITEM_ID <= 4200019)
