                            if (Database.ItemType.unabletradeitem.Contains(item.ITEM_ID) || item.Bound >= 1)
                            {
                                client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream, true);
                                ServerLogs.AddDropLog(client, item);
                                break;
