                                        item.Position = (ushort)Role.Flags.ConquerItem.RuneBag;
                                        if (!Database.ItemType.isRune(item.ITEM_ID))
                                            client.Send(stream.ItemUsageCreate(ItemUsuageID.RemoveInventory, item.UID, 0, 0, 0, 0, 0));

                                        item.Mode = Role.Flags.ItemMode.AddItem;
                                        item.Send(client, stream);
                                        client.Send(stream.ItemUsageCreate(action, id, dwParam, timestamp, dwParam2, dwParam3, dwparam4, args));
                                        client.Equipment.QueryEquipment(client.Equipment.Alternante);
                                        Database.RuneRank.Update(client);
                                    }
                                }
                            }
                            else
                            {
                                if (client.Rune.TryGetItem(id, out item) && item.Position == (ushort)Role.Flags.ConquerItem.RuneBag)
                                {
                                    if (client.Rune.Remove(id, false))
                                    {
                                        Database.ItemType.DBItem DBItem;
                                        if (Pool.ItemsBase.TryGetValue(item.ITEM_ID, out DBItem))
                                        {
                                            bool Bound = false;
                                            if (item.Bound > 0)
                                                Bound = true;
                                            TimeSpan timeSpan = item.TimeStamp - DateTime.Now;
                                            if (item.TimeLeftInMinutes > 0)
                                                client.Inventory.AddTime(stream, item.ITEM_ID, 0, 0, 0, Bound, (uint)timeSpan.TotalSeconds);
                                            else
                                                client.Inventory.AddItemWitchStack(item.ITEM_ID, 0, (ushort)item.StackSize, stream, Bound);
                                            client.Send(stream.ItemUsageCreate(action, id, dwParam, timestamp, dwParam2, dwParam3, dwparam4, args));
                                            Database.RuneRank.Update(client);
                                        }

                                    }
                                }
                            }
                        }
                        break;
                    }
                case ItemUsuageID.EquipRune:
                    {
                        if (client.Player.Reborn >= 2 && client.Player.Level >= 15)
                        {
                            MsgGameItem item;
                            if (client.Rune.TryGetItem(id, out item))
                            {
                                if (item != null)
                                {
                                    if (Database.ItemType.isRune(item.ITEM_ID))
                                    {
                                        ushort original = (ushort)dwParam;
                                        if (Database.ItemType.ItemPosition(item.ITEM_ID) != (ushort)Role.Flags.ConquerItem.RedRune)
                                            if (dwParam == (uint)Role.Flags.ConquerItem.RedRune || dwParam == (uint)Role.Flags.ConquerItem.AlternateRedRune)
                                                return;
                                        if (Database.ItemType.ItemPosition(item.ITEM_ID) != (ushort)Role.Flags.ConquerItem.BlueRune)
                                            if (dwParam == (uint)Role.Flags.ConquerItem.BlueRune || dwParam == (uint)Role.Flags.ConquerItem.AlternateBlueRune)
                                                return;
                                        if ((original >= (ushort)Role.Flags.ConquerItem.YellowRune && original <= ((ushort)Role.Flags.ConquerItem.YellowRune + 12)) || (original >= (ushort)Role.Flags.ConquerItem.AlternateYellowRune && original <= ((ushort)Role.Flags.ConquerItem.AlternateYellowRune + 12)))
                                            if (item.ITEM_ID / 10000 != 403 && item.ITEM_ID / 10000 != 407 && !(item.ITEM_ID >= 4070001 && item.ITEM_ID <= 4070009) && !(item.ITEM_ID >= 4070501 && item.ITEM_ID <= 4070509) && !(item.ITEM_ID >= 4071501 && item.ITEM_ID <= 4071509) && !(item.ITEM_ID >= 4072001 && item.ITEM_ID <= 4072009) && !(item.ITEM_ID == 4070609)) return;

                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.OneRune)
                                            != (uint)Role.Instance.Beasts.HammerRunes.OneRune)
                                        {
                                            if (original == 110 || original == 130)
                                                return;
                                        }
                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.TwoRune)
                                            != (uint)Role.Instance.Beasts.HammerRunes.TwoRune)
                                        {
                                            if (original == 111 || original == 131)
                                                return;
                                        }
                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.ThreeRune)
                                           != (uint)Role.Instance.Beasts.HammerRunes.ThreeRune)
                                        {
                                            if (original == 112 || original == 132)
                                                return;
                                        }
                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.FourRune)
                                           != (uint)Role.Instance.Beasts.HammerRunes.FourRune)
                                        {
                                            if (original == 113 || original == 133)
                                                return;
                                        }
                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.FiveRune)
                                          != (uint)Role.Instance.Beasts.HammerRunes.FiveRune)
                                        {
                                            if (original == 114 || original == 134)
                                                return;
                                        }
                                        if ((client.Beasts.Flag & (uint)Role.Instance.Beasts.HammerRunes.SixRune)
                                          != (uint)Role.Instance.Beasts.HammerRunes.SixRune)
                                        {
                                            if (original == 115 || original == 135)
                                                return;
                                        }
                                        ushort pos = Database.ItemType.ItemPosition(item.ITEM_ID);
                                        if (pos == (ushort)Role.Flags.ConquerItem.YellowRune && ((original > (ushort)Role.Flags.ConquerItem.YellowRune && original <= ((ushort)Role.Flags.ConquerItem.YellowRune + 12)) || (original > (ushort)Role.Flags.ConquerItem.AlternateYellowRune && original <= ((ushort)Role.Flags.ConquerItem.AlternateYellowRune + 12))))
                                        {
                                            pos = original;
                                        }
                                        if (dwParam > 120 && dwParam < 134 && pos < 120)
                                        {
                                            pos += 20;
                                        }
                                        if (pos % 10 > 5)
                                        {
                                            if (client.Beasts.Activated && client.Beasts.Level > 0)
                                            {
                                                if (Database.BeastsAtrribute.Attributes[client.Beasts.Level].YellowRuneSlots < (pos % 10) - 5) return;
                                            }
                                            else return;
                                        }

                                        if (client.Rune.Objects.Count(i => i.UID == item.UID && i.Position != (ushort)Role.Flags.ConquerItem.RunesCollection) > 0)
                                            return;
                                        if (client.Rune.Free((byte)pos) || client.Rune.Unequip(client.Rune.TryGetItem((byte)pos)))
                                            goto Equip;
                                        Equip:
                                        if (client.Rune.Equip(item, (byte)pos))
                                        {
                                            client.Send(stream.ItemUsageCreate(action, item.UID, dwParam, timestamp, dwParam2, dwParam3, dwparam4, args));
                                            client.Equipment.QueryEquipment(client.Equipment.Alternante);
                                            Database.RuneRank.Update(client);
                                        }
                                    }
                                }
                            }
                        }
                        else client.SendSysMesage("You need to be a second reborn hero to interact with rune system!");
                        break;
                    }

                case ItemUsuageID.UnequipRune:
                    {
                        if (client.Player.Reborn >= 2 && client.Player.Level >= 15)
                        {
                            if (!client.Inventory.HaveSpace(1))
                            {
                                client.CreateBoxDialog("Please free 1 more space in your inventory.");
                                break;
                            }
                            MsgGameItem item;
                            if (client.Rune.TryGetItem(id, out item))
                            {
                                if (item != null)
                                {
                                    if (client.Rune.Unequip(item))
                                    {
                                        client.Send(stream.ItemUsageCreate(action, item.UID, dwParam, timestamp, dwParam2, dwParam3, dwparam4, args));
                                        client.Equipment.QueryEquipment(client.Equipment.Alternante);
                                        Database.RuneRank.Update(client);
                                    }
                                }
                            }
                        }
                        else client.SendSysMesage("You need to be a second reborn hero to interact with rune system!");
                        break;
                    }
                
                case ItemUsuageID.EmbedAnima:
                    {
                        if (!client.Player.TREPIN2 && client.Player.CheckPin())
                        {
                            client.Player.MessageBox("Please Active Pincode", null, null, 60);
                            return;
                        }
                        MsgGameItem targetedEquipment, Anima;

                        if ((client.Inventory.TryGetItem(id, out targetedEquipment) || client.Equipment.TryGetValue(id, out targetedEquipment)) && client.Inventory.TryGetItem((uint)dwParam, out Anima))
                        {
                            if (Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Head
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Necklace
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Ring
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Armor
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.LeftWeapon
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.RightWeapon
                               || Database.ItemType.ItemPosition(targetedEquipment.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Boots)
                            {


                                var pos = targetedEquipment.Position;


                                if (!Database.ItemType.AllowToUpdate((Role.Flags.ConquerItem)pos))
                                    break;
                                if (!(Anima.ITEM_ID >= 4200001 && Anima.ITEM_ID <= 4200019))
                                    return;

                                if (client.Inventory.Remove(Anima.ITEM_ID, 1, stream))
                                {
                                    targetedEquipment.Mode = Role.Flags.ItemMode.Update;
                                    targetedEquipment.AnimaItemID = Anima.ITEM_ID;
                                    targetedEquipment.Send(client, stream);
                                    client.Equipment.QueryEquipment(client.Equipment.Alternante);
                                }
                            }
                        }
                        break;
                    }
                case ItemUsuageID.RemoveAnima:
                    {
                        if (!client.Player.TREPIN2 && client.Player.CheckPin())
                        {
                            client.Player.MessageBox("Please Active Pincode", null, null, 60);
                            return;
                        }
                        MsgGameItem targetedEquipment;

                        if (client.Inventory.TryGetItem(id, out targetedEquipment) || client.Equipment.TryGetValue(id, out targetedEquipment))
                        {
                            int Days = 0;
                            switch (targetedEquipment.AnimaItemID)
                            {
                                case 4200018:
                                    Days = 8;
                                    break;
                                case 4200017:
                                    Days = 8;
                                    break;
                                case 4200016:
                                    Days = 8;
                                    break;
                                case 4200015:
                                    Days = 5;
                                    break;
                                case 4200014:
                                    Days = 5;
                                    break;
                                case 4200013:
                                    Days = 3;
                                    break;
                                case 4200012:
                                    Days = 3;
                                    break;

                            }
                            if (client.Inventory.AddAnimaLock(stream, targetedEquipment.AnimaItemID, 0, 0))
                            {
                                targetedEquipment.AnimaItemID = 0;
                                targetedEquipment.Mode = Role.Flags.ItemMode.Update;
                                targetedEquipment.Send(client, stream);
                                client.Equipment.QueryEquipment(client.Equipment.Alternante);
                            }
                        }
                        break;
                    }
                case ItemUsuageID.Alternante:
                case ItemUsuageID.UnAlternante:
                    {
                        if (!(DateTime.Now > client.Player.EquipStamp.AddSeconds(1)))
                        {
                            client.SendSysMesage("You cannot switch between equipments Wait 1 Seconds!", MsgMessage.ChatMode.Talk, MsgMessage.MsgColor.red, false);
                            return;
                        }
                        client.Player.EquipStamp = DateTime.Now;
                        if (client.Equipment == null) break;
                        MsgGameItem Weapon;
                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteLeftWeapon, out Weapon))
                        {
                            if (Database.ItemType.IsKnife(Weapon.ITEM_ID))
                            {
                                client.SendSysMesage("Can't while wearing a knife.");
                                break;
                            }
                        }

                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteLeftWeapon, out Weapon))
                        {
                            if (client.Player.ContainFlag(MsgUpdate.Flags.FatalStrike))
                            {
                                if (!Database.ItemType.IsKatana(Weapon.ITEM_ID)
                                                           && !Database.ItemType.IsKatana(Weapon.ITEM_ID) || !Database.ItemType.IsNinjaEpicWeapon(Weapon.ITEM_ID)
                                                           && !Database.ItemType.IsNinjaEpicWeapon(Weapon.ITEM_ID))
                                {
                                    client.SendSysMesage("Can't while wearing a " + Pool.ItemsBase[Weapon.ITEM_ID].Name.ToString() + ".");
                                    break;
                                }
                            }
                        }
                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteRightWeapon, out Weapon))
                        {
                            if (!Database.AtributesStatus.IsWater(client.Player.Class) && Database.ItemType.IsTaoistEpicWeapon(Weapon.ITEM_ID) || Database.ItemType.IsBacksword(Weapon.ITEM_ID))
                            {
                                client.SendSysMesage("Can't while wearing a BackSword.");
                                break;
                            }
                        }

                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteRightWeapon, out Weapon))
                        {
                            if (Database.ItemType.IsKnife(Weapon.ITEM_ID))
                            {
                                client.SendSysMesage("Can't while wearing a knife.");
                                break;
                            }
                        }
                        #region Remove Skill
                        if (client.Player.ContainFlag(MsgUpdate.Flags.IronShield))
                        {
                            client.SendSysMesage("Please remove the effect rune IronShield.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.Slayer))
                        {
                            client.SendSysMesage("Please remove the effect rune Slayer.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.NeptuneCurse))
                        {
                            client.SendSysMesage("Please remove the effect rune NeptuneCurse.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.PortadorRuneDuel))
                        {
                            client.SendSysMesage("Please remove the effect rune Duel.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.Absolution))
                        {
                            client.SendSysMesage("Please remove the effect rune Duel.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.ShadowFist))
                        {
                            client.SendSysMesage("Please remove the effect rune ShadowFist.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.CounterPunch))
                        {
                            client.SendSysMesage("Please remove the effect rune CounterPunch.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.RiseofTaoism))
                        {
                            client.SendSysMesage("Please remove the effect rune RiseofTaoism.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.FireCurse))
                        {
                            client.SendSysMesage("Please remove the effect rune FireCurse.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.BloodTide))
                        {
                            client.SendSysMesage("Please remove the effect rune BloodTide.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.Rampage))
                        {
                            client.SendSysMesage("Please remove the effect rune Rampage.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.Infinity))
                        {
                            client.SendSysMesage("Please remove the effect rune Infinity.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.StarRaid))
                        {
                            client.SendSysMesage("Please remove the effect rune StarRaid.");
                            break;
                        }
                        #endregion
                        if (client.Player.ContainFlag(MsgUpdate.Flags.PathOfShadow))
                        {
                            client.SendSysMesage("Please remove the PathOfShadow.");
                            break;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.Fly))
                            break;

                        if (client.Player.SpecialGarment != 0)
                        {

                            client.SendSysMesage("Item can't be unequiped during the event.");
                            return;
                        }

                        if (client.Inventory.HaveSpace(1))
                        {
                            client.OnAutoAttack = false;
                            client.Equipment.Alternante = !client.Equipment.Alternante;
                            client.Equipment.QueryEquipment(client.Equipment.Alternante);
                            client.Player.View.ReSendView(stream);
                            client.MyNinja.Alternate();
                        }
                        else
                        {
                            client.SendSysMesage("Your Inventory Is Full!");

                        }
                        break;
                    }
                default:
                    {
                        if (action > 0)
                            MyConsole.WriteLine(" [" + client.Player.Name + "] MsgItemUsuagePacket  not find -> " + action);

                        break;
                    }
            }
        }

        public unsafe static void AlternanteEquipItem(Client.GameClient client, ServerSockets.Packet stream, uint id, uint dwParam1, uint timestamp, uint dwParam2, uint dwParam3, uint dwparam4)
        {

            uint Position = dwParam1;
            Position -= 50;
            Game.MsgServer.MsgGameItem item = null;
            if (client.Inventory.TryGetItem(id, out item))
            {
                if (Database.ItemType.ItemPosition(item.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Garment)
                {
                    if (client.Player.SpecialGarment != 0)
                    {

                        client.SendSysMesage("Item can't be unequiped during the event.");

                        client.SendSysMesage("Item can't be unequiped during the event.");


                        return;
                    }
                }
                if (Database.ItemType.IsPistol(item.ITEM_ID))
                {
                    if (client.Equipment.FreeEquip(Role.Flags.ConquerItem.RightWeapon))
                        return;
                    Game.MsgServer.MsgGameItem rapier;
                    if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.RightWeapon, out rapier))
                    {
                        if (!Database.ItemType.IsRapier(rapier.ITEM_ID))
                            return;
                    }
                    else
                        return;
                }
                if (Position == (ushort)Role.Flags.ConquerItem.LeftWeapon)
                {
                    if (Database.ItemType.IsKnife(client.Equipment.RightWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID) == false)
                        {
                            client.SendSysMesage("Remove the right-hand Knife.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                }
                if (Position == (ushort)Role.Flags.ConquerItem.RightWeapon)
                {
                    if (Database.ItemType.IsKnife(client.Equipment.LeftWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID) == false)
                        {
                            client.SendSysMesage("Remove the left-hand Knife.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                    if (Database.ItemType.IsShield(client.Equipment.LeftWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID))
                        {
                            client.SendSysMesage("Remove the left-hand Shield.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                    if (Database.ItemType.IsTaoistEpicWeapon(client.Equipment.RightWeapon))
                    {
                        if (!Database.AtributesStatus.IsWater(client.Player.Class))
                        {
                            if (Database.ItemType.IsTaoistEpicWeapon(item.ITEM_ID))
                            {
                                client.SendSysMesage("Remove the left-hand IsTaoistEpicWeapon.", MsgMessage.ChatMode.System);
                                return;
                            }
                        }
                    }
                }
                bool can2hand = false;
                bool can2wpn = false;
                if (client.Player.Class >= 1001 && client.Player.Class <= 8057)
                    can2hand = true;
                if (Database.AtributesStatus.IsTaoist(client.Player.Class) || Database.AtributesStatus.IsTrojan(client.Player.Class) || Database.AtributesStatus.IsWarrior(client.Player.Class) || client.Player.Class >= 5001 && client.Player.Class <= 8057)
                    can2wpn = true;

                if (Database.AtributesStatus.IsArcher(client.Player.Class))
                {
                    if (Database.ItemType.IsTwoHand(item.ITEM_ID) && client.Player.IsAsasin)
                        return;

                    can2wpn = true;
                }
                if (!Database.ItemType.Equipable(item, client))
                    return;
                ushort po = Database.ItemType.ItemPosition(item.ITEM_ID);
                if (Database.AtributesStatus.IsTaoist(client.Player.Class))
                {
                    if (po == (ushort)Role.Flags.ConquerItem.LeftWeapon)
                    {
                        if (Database.ItemType.IsHossu(item.ITEM_ID) == false)
                            return;
                    }
                }
                if (po == (ushort)Role.Flags.ConquerItem.Garment || po == (ushort)Role.Flags.ConquerItem.SteedMount)
                    return;
                if (po == 5)
                {
                    Position = 5;
                    if (!can2hand && !can2wpn)
                        return;
                    if (!client.Equipment.FreeEquip(Role.Flags.ConquerItem.AleternanteRightWeapon))
                    {
                        Game.MsgServer.MsgGameItem RightWeapon;
                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteRightWeapon, out RightWeapon))
                        {
                            if (RightWeapon.ITEM_ID / 1000 != 500 && Database.ItemType.IsArrow(item.ITEM_ID))
                                return;
                        }
                    }
                    else
                        return;
                }
                else if (po == 0) return;
                if (Database.ItemType.ItemPosition(item.ITEM_ID) == 4)
                {
                    if (Position == 5)
                        if (!can2hand || !can2wpn)
                            return;
                }
                if (!((Position == 4 || Position == 5) && (Database.ItemType.ItemPosition(item.ITEM_ID) == 4 || Database.ItemType.ItemPosition(item.ITEM_ID) == 5)))
                {
                    if (!Database.ItemType.IsAccessory(item.ITEM_ID))
                        Position = Database.ItemType.ItemPosition(item.ITEM_ID);
                }
                bool twohand = Database.ItemType.IsTwoHand(item.ITEM_ID);
                if (!twohand && Position == 4)
                {
                    Game.MsgServer.MsgGameItem LeftWeapon;
                    if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteLeftWeapon, out LeftWeapon))
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            if (Database.ItemType.IsArrow(LeftWeapon.ITEM_ID))
                                client.Equipment.Remove(Role.Flags.ConquerItem.AleternanteLeftWeapon, stream);
                            else
                            {
                                Game.MsgServer.MsgGameItem RightWeapon;
                                if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.AleternanteRightWeapon, out RightWeapon))
                                {
                                    if (Database.ItemType.IsTwoHand(RightWeapon.ITEM_ID))
                                        client.Equipment.Remove(Role.Flags.ConquerItem.AleternanteRightWeapon, stream);
                                }
                            }
                        }
                    }
                }
                Position += 50;
                if (client.Equipment.FreeEquip((Role.Flags.ConquerItem)Position))
                {
                    bool spaceinventory = true;
                    if (twohand)
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            client.Equipment.Remove(Role.Flags.ConquerItem.AleternanteLeftWeapon, stream);
                        }
                        else
                        {
                            spaceinventory = false;
                        }
                    }
                    if (spaceinventory)
                    {
                        client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                        item.Position = (ushort)Position;
                        client.Equipment.Add(item, stream);
                        item.Mode = Role.Flags.ItemMode.Update;
                        item.Send(client, stream);
                    }
                }
                else//if is item on character
                {
                    bool spaceinventory = true;
                    if (twohand)
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            client.Equipment.Remove(Role.Flags.ConquerItem.AleternanteLeftWeapon, stream);
                        }
                        else
                            spaceinventory = false;
                    }
                    if (spaceinventory)
                    {
                        client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                        item.Position = (ushort)Position;
                        item.Mode = Role.Flags.ItemMode.AddItem;

                        client.Equipment.Remove((Role.Flags.ConquerItem)Position, stream);
                        client.Equipment.Add(item, stream);
                    }
                }

                Game.MsgServer.MsgShowEquipment equip = new MsgShowEquipment();
                equip.wParam = item.UID;
                equip.Alternante = item.Position;
                equip.UID = 5;
                client.Send(stream.ShowEquipmentCreate(equip));
                if (client.Equipment.Alternante)
                {
                    client.Equipment.QueryEquipment(true);
                }
                else
                    client.Equipment.SendAlowAlternante(stream);
                client.Equipment.QueryEquipment(client.Equipment.Alternante);
            }
        }
        public unsafe static void EquipItem(Client.GameClient client, ServerSockets.Packet stream, uint id, uint dwParam1, uint timestamp, uint dwParam2, uint dwParam3, uint dwparam4)
        {
            uint Position = dwParam1;

            Game.MsgServer.MsgGameItem item = null;
            if (client.Inventory.TryGetItem(id, out item))
            {

                switch (item.ITEM_ID)
                {
                    case 1200000:
                    case 1200001:
                    case 1200002:
                        {
                            UseItem(item, client, stream);
                            return;
                        }
                    default:
                        {
                            if (Position == 17 && Database.ItemType.ItemPosition(item.ITEM_ID) == 0)
                            {
                                UseItem(item, client, stream);
                                return;
                            }
                            else if (Position == 0 && Database.ItemType.ItemPosition(item.ITEM_ID) == 0)
                            {
                                UseItem(item, client, stream);
                                return;
                            }
                            break;
                        }
                }

                if (client.Player.ContainFlag(MsgUpdate.Flags.PathOfShadow))
                {
#if Arabic
                      client.SendSysMesage("Please remove you PathOfShadow.");
#else
                    client.SendSysMesage("Please remove you PathOfShadow.");
#endif

                    return;
                }
                if (Database.ItemType.ItemPosition(item.ITEM_ID) == (ushort)Role.Flags.ConquerItem.Garment)
                {
                    if (client.Player.SpecialGarment != 0)
                    {
#if Arabic
                           client.SendSysMesage("Item can't be unequiped during the event.");
#else
                        client.SendSysMesage("Item can't be unequiped during the event.");
#endif

                        return;
                    }
                }
                if (item.ITEM_ID == 2169165)
                {
                    client.Player.AddSpecialFootprint((Game.MsgServer.MsgTitleStorage.Footprint.BlazesFootprint), stream);
                    client.Player.AddSpecialHaloAction((Game.MsgServer.MsgTitleStorage.HaloAction.BlazesAction), stream);
                }
                if (item.ITEM_ID == 2100095)
                {
                    client.Player.AddSpecialFootprint((Game.MsgServer.MsgTitleStorage.Footprint.LotusGrace1), stream);
                    client.Player.AddSpecialHaloAction((Game.MsgServer.MsgTitleStorage.HaloAction.SupremeAlone), stream);
                }
                if (item.ITEM_ID == 2169645)
                {
                    client.Player.AddSpecialFootprint((Game.MsgServer.MsgTitleStorage.Footprint.BlazesFootprint1), stream);
                    client.Player.AddSpecialHaloAction((Game.MsgServer.MsgTitleStorage.HaloAction.BlazesAction3), stream);
                }
                if (item.ITEM_ID / 1000 == 900)
                {

                    if (!Database.AtributesStatus.IsWarrior(client.Player.Class) && !Database.AtributesStatus.IsMonk(client.Player.Class))
                        return;
                }
                if (item.ITEM_ID / 1000 == 613)
                {
                    if (!Database.AtributesStatus.IsArcher(client.Player.Class))
                        return;
                }
                if (item.ITEM_ID / 1000 == 608)
                {
                    if (!Database.AtributesStatus.IsDune(client.Player.Class))
                    {
                        return;
                    }
                }
                if (Database.ItemType.IsPistol(item.ITEM_ID))
                {
                    if (client.Equipment.FreeEquip(Role.Flags.ConquerItem.RightWeapon))
                        return;
                    Game.MsgServer.MsgGameItem rapier;
                    if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.RightWeapon, out rapier))
                    {
                        if (!Database.ItemType.IsRapier(rapier.ITEM_ID))
                            return;
                    }
                    else
                        return;
                }


                bool can2hand = false;
                bool can2wpn = false;
                if (client.Player.Class >= 1001 && client.Player.Class <= 8057 || Database.AtributesStatus.IsWindWalker(client.Player.Class) || Database.AtributesStatus.IsDune(client.Player.Class))
                    can2hand = true;
                if (Database.AtributesStatus.IsTrojan(client.Player.Class) || Database.AtributesStatus.IsWarrior(client.Player.Class) || client.Player.Class >= 5001 && client.Player.Class <= 14057
                    || Database.AtributesStatus.IsWindWalker(client.Player.Class) || Database.AtributesStatus.IsDune(client.Player.Class))
                    can2wpn = true;

                if (Database.AtributesStatus.IsArcher(client.Player.Class))
                {
                    if (Database.ItemType.IsTwoHand(item.ITEM_ID) && client.Player.IsAsasin)
                        return;

                    can2wpn = true;
                }
                if (!Database.ItemType.Equipable(item, client))
                    return;
                ushort po = Database.ItemType.ItemPosition(item.ITEM_ID);
                if (Database.AtributesStatus.IsTaoist(client.Player.Class))
                {
                    if (po == (ushort)Role.Flags.ConquerItem.LeftWeapon)
                    {
                        if (Database.ItemType.IsHossu(item.ITEM_ID) == false)
                            return;
                    }
                }
                if (Position == 5)
                {
                    if (Database.ItemType.IsTwoHand(client.Equipment.RightWeapon))
                    {
                        if (Database.ItemType.IsShield(item.ITEM_ID) == false && Database.ItemType.IsHossu(item.ITEM_ID) == false)
                            return;
                    }
                }
                if (Position == (ushort)Role.Flags.ConquerItem.LeftWeapon)
                {
                    if (Database.ItemType.IsKnife(client.Equipment.RightWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID) == false)
                        {
                            client.SendSysMesage("Remove the right-hand Knife.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                }

                if (Position == (ushort)Role.Flags.ConquerItem.LeftWeapon)
                {
                    if (Database.ItemType.IsBacksword(client.Equipment.RightWeapon))
                    {
                        if (Database.ItemType.IsShield(item.ITEM_ID) == false && Database.ItemType.IsHossu(item.ITEM_ID) == false)
                            return;
                    }
                }
                if (client.Player.Class >= 10000 && client.Player.Class <= 14057)
                {
                    if (Database.ItemType.IsShield(item.ITEM_ID) == true)
                        return;
                }
                if (Position == (ushort)Role.Flags.ConquerItem.RightWeapon)
                {
                    if (Database.ItemType.IsKnife(client.Equipment.LeftWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID) == false)
                        {
                            client.SendSysMesage("Remove the left-hand Knife.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                    if (Database.ItemType.IsShield(client.Equipment.LeftWeapon))
                    {
                        if (Database.ItemType.IsKnife(item.ITEM_ID))
                        {
                            client.SendSysMesage("Remove the left-hand Shield.", MsgMessage.ChatMode.System);
                            return;
                        }
                    }
                }

                if (po == (ushort)Role.Flags.ConquerItem.Garment || po == (ushort)Role.Flags.ConquerItem.SteedMount)
                    return;
                if (po == 5)
                {
                    Position = 5;
                    if (!can2hand && !can2wpn)
                        return;
                    if (!client.Equipment.FreeEquip(Role.Flags.ConquerItem.RightWeapon))
                    {
                        Game.MsgServer.MsgGameItem RightWeapon;
                        if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.RightWeapon, out RightWeapon))
                        {
                            if (RightWeapon.ITEM_ID / 1000 != 500 && Database.ItemType.IsArrow(item.ITEM_ID))
                                return;
                        }
                    }
                    else
                        return;
                }
                else if (po == 0) return;
                if (Database.ItemType.ItemPosition(item.ITEM_ID) == 4)
                {
                    if (Position == 5)
                        if (!can2hand || !can2wpn)
                            return;
                }
                if (!((Position == 4 || Position == 5) && (Database.ItemType.ItemPosition(item.ITEM_ID) == 4 || Database.ItemType.ItemPosition(item.ITEM_ID) == 5)))
                {
                    if (!Database.ItemType.IsAccessory(item.ITEM_ID))
                        Position = Database.ItemType.ItemPosition(item.ITEM_ID);
                }
                bool twohand = Database.ItemType.IsTwoHand(item.ITEM_ID);
                if (!twohand && Position == 4)
                {
                    Game.MsgServer.MsgGameItem LeftWeapon;
                    if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.LeftWeapon, out LeftWeapon))
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            if (Database.ItemType.IsArrow(LeftWeapon.ITEM_ID))
                                client.Equipment.Remove(Role.Flags.ConquerItem.LeftWeapon, stream);
                            else
                            {
                                Game.MsgServer.MsgGameItem RightWeapon;
                                if (client.Equipment.TryGetEquip(Role.Flags.ConquerItem.RightWeapon, out RightWeapon))
                                {
                                    if (Database.ItemType.IsTwoHand(RightWeapon.ITEM_ID))
                                        client.Equipment.Remove(Role.Flags.ConquerItem.RightWeapon, stream);
                                }
                            }
                        }
                    }
                }
                if (client.Equipment.FreeEquip((Role.Flags.ConquerItem)Position))
                {
                    bool spaceinventory = true;
                    if (twohand)
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            client.Equipment.Remove(Role.Flags.ConquerItem.LeftWeapon, stream);
                        }
                        else
                        {
                            spaceinventory = false;
                        }
                    }
                    if (spaceinventory)
                    {
                        client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                        item.Position = (ushort)Position;
                        client.Equipment.Add(item, stream);
                        item.Mode = Role.Flags.ItemMode.Update;
                        item.Send(client, stream);
                    }
                }
                else//if is item on character
                {
                    bool spaceinventory = true;
                    if (twohand)
                    {
                        if (client.Inventory.HaveSpace(1))
                        {
                            client.Equipment.Remove(Role.Flags.ConquerItem.LeftWeapon, stream);
                        }
                        else
                            spaceinventory = false;
                    }
                    if (spaceinventory)
                    {
                        client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                        item.Position = (ushort)Position;
                        item.Mode = Role.Flags.ItemMode.AddItem;

                        client.Equipment.Remove((Role.Flags.ConquerItem)Position, stream);
                        client.Equipment.Add(item, stream);
                    }
                }
                client.OnAutoAttack = false;
                client.Equipment.QueryEquipment(client.Equipment.Alternante);
            }
        }

        public static void UseItem(Game.MsgServer.MsgGameItem item, Client.GameClient client, ServerSockets.Packet stream)
        {

            if (!client.Player.Alive)
                return;

            if (client.InTrade || client.PokerPlayer != null)
                return;

            Database.ItemType.DBItem DBItem;
            if (Pool.ItemsBase.TryGetValue(item.ITEM_ID, out DBItem))
            {
                if (client.PipeServer != null)
                {
                    if (item.ITEM_ID >= 1000000 && item.ITEM_ID <= 1000040
                  || item.ITEM_ID >= 1002000 && item.ITEM_ID <= 1002030
                  || item.ITEM_ID == 1002050
                  || item.ITEM_ID == 725065 || item.ITEM_ID == 1003010)
                    {
                        if (DateTime.Now > client.Player.MedicineStamp.AddMilliseconds(150))
                        {
                            if (client.Player.ContainFlag(MsgUpdate.Flags.PoisonStar))
                                return;
                            if (client.Player.HitPoints == client.Status.MaxHitpoints)
                                return;
                            if (Program.NoHP.Contains(client.Player.Map))
                            {
                                client.SendSysMesage("No HP In This Map WorldConquer .");
                                return;
                            }
                            int maxHP = (int)client.Status.MaxHitpoints;
                            if (Time32.Now < client.Player.DuelEndStamp.AddSeconds(20))
                                maxHP = (int)((double)maxHP * (double)client.Player.DuelPercent / 100d);
                            #region MiracleTouch
                            byte MiracleTouchLevel = 0;
                            if (client.Player.Owner.Rune.IsEquipped("MiracleTouch", ref MiracleTouchLevel))
                            {
                                uint Increases = 0;
                                switch (MiracleTouchLevel)
                                {
                                    case 1: Increases = 10000; break;
                                    case 2: Increases = 11000; break;
                                    case 3: Increases = 12000; break;
                                    case 4: Increases = 13000; break;
                                    case 5: Increases = 14000; break;
                                    case 6: Increases = 15000; break;
                                    case 7: Increases = 16000; break;
                                    case 8: Increases = 18000; break;
                                    case 9: Increases = 20000; break;
                                }
                                client.Player.HitPoints += (int)Increases;

                            }
                            #endregion
                            uint ItemHP = DBItem.ItemHP;

                            client.Player.HitPoints = Math.Min(client.Player.HitPoints + DBItem.ItemHP, (int)client.Status.MaxHitpoints);
                            client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                            client.Player.MedicineStamp = DateTime.Now;
                        }
                    }
                    else if (item.ITEM_ID >= 1001000 && item.ITEM_ID <= 1001040
                        || item.ITEM_ID == 1002030 || item.ITEM_ID == 1002040
                        || item.ITEM_ID == 725066 || item.ITEM_ID == 1004010)
                    {
                        if (client.Player.ContainFlag(MsgUpdate.Flags.PoisonStar))
                            return;

                        if (Program.NoHP.Contains(client.Player.Map))
                        {
                            client.SendSysMesage("No HP In This Map WorldConquer .");
                            return;
                        }
                        if (client.Player.Mana == client.Status.MaxMana)
                            return;
                        int maxMana = (int)client.Status.MaxMana;
                        if (Time32.Now < client.Player.DuelEndStamp.AddSeconds(20))
                            maxMana = (int)((double)maxMana * (double)client.Player.DuelPercent / 100d);

                        client.Player.Mana = (ushort)Math.Min(client.Player.Mana + DBItem.ItemMP, (int)client.Status.MaxMana);
                        client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                    }
                    return;
                }
                else if (client.IsConnectedInterServer())
                {
                    return;
                }

                #region HouseItems
                if (item.ITEM_ID >= 726001 && item.ITEM_ID <= 726108 || item.ITEM_ID == 722559// item box.
                || item.ITEM_ID >= 721177 && item.ITEM_ID <= 721202)
                {
                    if (Database.HouseTable.InHouse(client.Player.Map) && client.Player.DynamicID == client.Player.UID)
                    {
                        NpcServerQuery Furniture = new NpcServerQuery();
                        if (item.ITEM_ID == 722559)
                            Furniture.NpcType = Role.Flags.NpcType.Talker;
                        else
                            Furniture.NpcType = Role.Flags.NpcType.Furniture;

                        Furniture.Action = MsgNpc.NpcServerReplay.Mode.Cursor;
                        var Npc = Database.NpcServer.GetNpc(item.ITEM_ID);
                        if (Npc != null)
                        {
                            client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);

                            Furniture.Mesh = Npc.Mesh;
                            Furniture.ID = (MsgNpc.NpcID)Npc.UID;
                            client.MoveNpcMesh = Furniture.Mesh;
                            client.MoveNpcUID = (uint)Furniture.ID;
                            client.Send(stream.NpcServerCreate(Furniture));
                        }
                    }
                    else
                    {
                        client.SendSysMesage("You have to be in your own house to be able to display it.", MsgMessage.ChatMode.System, MsgMessage.MsgColor.red);
                    }
                    return;
                }
                #endregion

                if (item.ITEM_ID >= 1000000 && item.ITEM_ID <= 1000040
                || item.ITEM_ID >= 1002000 && item.ITEM_ID <= 1002030
                || item.ITEM_ID == 1002050
                || item.ITEM_ID == 725065 || item.ITEM_ID == 1003010)
                {
                    if (client.Player.ContainFlag(MsgUpdate.Flags.ArchShadow))
                    {
                        if (DateTime.Now > client.Player.MedicineStamp.AddMilliseconds(250))
                        {
                            int maxHPP = (int)client.Status.MaxHitpoints;
                            if (Time32.Now < client.Player.DuelEndStamp.AddSeconds(20))
                                maxHPP = (int)((double)maxHPP * (double)client.Player.DuelPercent / 100d);
                            #region MiracleTouch
                            byte itemLevel = 0;
                            if (client.Player.Owner.Rune.IsEquipped("MiracleTouch", ref itemLevel))
                            {
                                uint percent = 0;
                                switch (itemLevel)
                                {
                                    case 1: percent = 10000; break;
                                    case 2: percent = 11000; break;
                                    case 3: percent = 12000; break;
                                    case 4: percent = 13000; break;
                                    case 5: percent = 14000; break;
                                    case 6: percent = 15000; break;
                                    case 7: percent = 16000; break;
                                    case 8: percent = 18000; break;
                                    case 9: percent = 20000; break;
                                }
                                client.Player.HitPoints += (int)percent;

                            }
                            #endregion
                            uint ItemHP = DBItem.ItemHP;

                            client.Player.HitPoints = Math.Min(client.Player.HitPoints + DBItem.ItemHP, maxHPP);
                            client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                            return;
                        }
                    }

                    if (client.Player.ContainFlag((MsgUpdate.Flags)279) && item.ITEM_ID != 1003010)
                        return;
                    if (client.Player.ContainFlag(MsgUpdate.Flags.PoisonStar) && item.ITEM_ID != 1003010)
                        return;
                    if (client.Player.HitPoints == client.Status.MaxHitpoints)
                        return;
                    if (Program.NoHP.Contains(client.Player.Map))
                    {
                        client.SendSysMesage("No HP In This Map.");
                        return;
                    }
                    int maxHP = (int)client.Status.MaxHitpoints;
                    if (Time32.Now < client.Player.DuelEndStamp.AddSeconds(20))
                        maxHP = (int)((double)maxHP * (double)client.Player.DuelPercent / 100d);
                    #region MiracleTouch
                    byte itemLevels = 0;
                    if (client.Player.Owner.Rune.IsEquipped("MiracleTouch", ref itemLevels) || client.Player.Owner.Rune.IsEquipped("Unbreakable", ref itemLevels))
                    {
                        uint percent = 0;
                        switch (itemLevels)
                        {
                            case 1: percent = 10000; break;
                            case 2: percent = 11000; break;
                            case 3: percent = 12000; break;
                            case 4: percent = 13000; break;
                            case 5: percent = 14000; break;
                            case 6: percent = 15000; break;
                            case 7: percent = 16000; break;
                            case 8: percent = 18000; break;
                            case 9: percent = 20000; break;
                        }
                        client.Player.HitPoints += (int)percent;

                    }
                    #endregion
                    if (client.Player.ContainFlag(MsgUpdate.Flags.Duel))
                    {
                        int ItemHP = (int)((double)DBItem.ItemHP * (double)client.Player.DuelPercent / 100d);
                        client.Player.HitPoints = Math.Min(client.Player.HitPoints + ItemHP, maxHP);
                    }
                    else
                    {
                        uint Reduces = 0;
                        if (client.Player.ContainFlag(MsgUpdate.Flags.PrisonSigilFutility))
                        {
                            Reduces = (uint)(DBItem.ItemHP * client.Player.FutilityDg) / 100;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.FrostPostion))
                        {
                            Reduces = (uint)(DBItem.ItemHP * 50) / 100;
                        }
                        if (client.Player.ContainFlag(MsgUpdate.Flags.FloraWard) || client.Player.ContainFlag(MsgUpdate.Flags.FineRain1))
                        {
                            if (client.Player.ContainFlag(MsgUpdate.Flags.FloraWard))
                            {
                                Database.MagicType.Magic DBSpell;
                                MsgSpell ClientSpell;
                                if (client.MySpells.ClientSpells.TryGetValue((ushort)Role.Flags.SpellID.FloraWard, out ClientSpell))
                                {
                                    Dictionary<ushort, Database.MagicType.Magic> DBSpells;
                                    if (Pool.Magic.TryGetValue((ushort)Role.Flags.SpellID.FloraWard, out DBSpells))
                                    {
                                        if (DBSpells.TryGetValue(ClientSpell.Level, out DBSpell))
                                        {
                                            client.Player.HitPoints = Math.Min(client.Player.HitPoints + (int)(DBItem.ItemHP - Reduces) * (DBSpell.GDamage / 100), maxHP);

                                        }
                                    }
                                }
                            }
                            else if (client.Player.ContainFlag(MsgUpdate.Flags.FineRain1) && client.Player.FineRainHit)
                            {
                                client.Player.FineRainPower = (uint)Math.Min(client.Player.FineRainPower + (int)(DBItem.ItemHP - Reduces), client.Player.FineRainHP);
                            }

                        }
                        else
                        {
                            client.Player.HitPoints = Math.Min(client.Player.HitPoints + (int)(DBItem.ItemHP - Reduces), maxHP);

                        }

                    }

                    client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                }
                else if (item.ITEM_ID >= 1001000 && item.ITEM_ID <= 1001040
                    || item.ITEM_ID == 1002030 || item.ITEM_ID == 1002040
                    || item.ITEM_ID == 725066 || item.ITEM_ID == 1004010)
                {


                    if (Program.NoHP.Contains(client.Player.Map))
                    {
                        client.SendSysMesage("No HP In This Map WorldConquer .");
                        return;
                    }
                    if (client.Player.Mana == client.Status.MaxMana)
                        return;
                    int maxMana = (int)client.Status.MaxMana;
                    if (Time32.Now < client.Player.DuelEndStamp.AddSeconds(20))
                        maxMana = (int)((double)maxMana * (double)client.Player.DuelPercent / 100d);

                    client.Player.Mana = (ushort)Math.Min(client.Player.Mana + DBItem.ItemMP, (int)client.Status.MaxMana);
                    client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                }
                else if (item.ITEM_ID >= 725000 && item.ITEM_ID <= 725044 || item.ITEM_ID == 1060101
              || item.ITEM_ID == 723701 || item.ITEM_ID == 727380 || item.ITEM_ID == 728094 || item.ITEM_ID == 721158 || item.ITEM_ID == 721157 || item.ITEM_ID == 3007568 || item.ITEM_ID == 3007567 || item.ITEM_ID == 727266 || item.ITEM_ID == 3007566 || item.ITEM_ID == 3316568 || item.ITEM_ID == 728231 || item.ITEM_ID >= 3006017 && item.ITEM_ID <= 3006020)//skills books
                {
                    switch (item.ITEM_ID)
                    {
                        #region StuffPack
                        case 727266:
                            {
                                client.Inventory.Update(item, Role.Instance.AddMode.REMOVE, stream);
                                client.Inventory.AddPrize(stream, 300000, 1, 6, 0, 0, Role.Flags.Gem.NoSocket, Role.Flags.Gem.NoSocket, true); // horse
                                client.Inventory.AddPrize(stream, 203009, 1, 6, 0, 0, Role.Flags.Gem.NoSocket, Role.Flags.Gem.NoSocket, true); // crop
                                client.Inventory.AddPrize(stream, 202009, 1, 6, 0, 0, Role.Flags.Gem.SuperGloryGem, Role.Flags.Gem.SuperGloryGem, true); // twoer
                                client.Inventory.AddPrize(stream, 201009, 1, 6, 0, 0, Role.Flags.Gem.SuperThunderGem, Role.Flags.Gem.SuperThunderGem, true); // fan
                                client.Inventory.AddPrize(stream, 204009, 1, 6, 0, 0, Role.Flags.Gem.SuperThunderGem, Role.Flags.Gem.SuperGloryGem, true); // Wing

                                if (Database.AtributesStatus.IsTrojan(client.Player.Class))
                                {
                                    client.Inventory.AddPrize(stream, 120269, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 150269, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 160249, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                   
                                    client.Inventory.AddPrize(stream, 130309, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 118309, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 420439, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 410439, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 480439, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);

                                    client.Inventory.AddPrize(stream, 614439, 2, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);//Epic

                                    client.Inventory.AddPrize(stream, 481439, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);//
                                    

                                }
                                if (Database.AtributesStatus.IsWarrior(client.Player.Class))
                                {

                                    client.Inventory.AddPrize(stream, 120269, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 150269, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 160249, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                   
                                    client.Inventory.AddPrize(stream, 131309, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                    client.Inventory.AddPrize(stream, 111309, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
                                   
                                    client.Inventory.AddPrize(stream, 561439, 1, 6, 0, 230, Role.Flags.Gem.SuperDragonGem, Role.Flags.Gem.SuperDragonGem, true);
