                        #region SigilBoxScrap
                        case 3327202:
                            {
                                if (item.Bound == 1)
                                {
                                    if (client.Inventory.Contain(item.ITEM_ID, 15, 1))
                                    {
                                        if (client.Inventory.Remove(item.ITEM_ID, 15, stream))
                                        {
                                            uint[] Items = new uint[] { 3330028, 3330029, 3330030, 3330031, 3330032, 3330033, 3330034, 3330035, 3330036, 3330037, 3330038, 3330039, 3330040, 3330042, 3330043, 3330044, 3330045, 3330046, 3330047, 3330048, 3330049, 3330050, 3330051, 3330052, 3330053, 3330054, 3330055, 3330056 };
                                            uint ID = 0;
                                            if (Role.Core.Rate(30))
                                            {
                                                uint[] Itemss = new uint[]
                                {
                              3330041, 3330057
                                };
                                                ID = Itemss[(uint)Pool.GetRandom.Next(0, Itemss.Length)];
                                            }

                                            else
                                                ID = Items[(uint)Pool.GetRandom.Next(0, Items.Length)];
                                            client.Inventory.Add(stream, ID, 1, 0, 0, 0, Role.Flags.Gem.NoSocket, Role.Flags.Gem.NoSocket, true);
                                            client.SendSysMesage("You have got 1 " + Pool.ItemsBase[ID].Name + "!.");
                                        }
                                    }
                                    else client.SendSysMesage("You don't have 15 SigilBoxScrap(B)!.");
                                }
